select 
  from batch.asset_freshness_policy
 where tenant_id = #{tenantId}
   and asset_type = 'JOB'

   and asset_code = #{assetCode}


   and enabled = #{enabled}

 order by enabled desc, asset_code asc
 limit #{limit}

select 
  from batch.asset_freshness_policy
 where tenant_id = #{tenantId}
   and id = #{id}
 limit 1

mapper.update:
update batch.asset_freshness_policy
   set enabled = #{enabled},
       updated_at = current_timestamp
 where tenant_id = #{tenantId}
   and id = #{id}
